            const data = await fetchModelList(token);
            const ids = (data.data || []).map(m => m.id);
            showResult(`
                <div class="bg-gray-800 border border-gray-700 rounded-lg p-4 mb-3">
                    <h4 class="text-white font-bold mb-3">사용 가능한 모델 (${ids.length}개)</h4>
