                key: '',
                format: 'openai',
                sysfirst: false,
                mergesys: false,
                altrole: false,
                mustuser: false,
                maxout: false,
                decoupled: false,
                thought: false,
                reasoning: 'none',
                verbosity: 'none',
                thinking: 'none',
                tok: 'o200k_base',
                customParams: '',
            };
            const result = CPM.addCustomModel(modelDef, 'copilot-auto');
